  ('locality-d0d1b9a2-moex-00555', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央公共債務會計制度之規定，其會計科目編號採幾位數？又分為幾組？', '["3位數、2組", "4位數、3組", "6位數、4組", "9位數、5組"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00556', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，當中央各機關收到各項收入，依其收入性質，貸 記各項收入科目外，並借記「各機關－在途現金」科目時，係屬下列何種情況應為之會計紀錄？', '["代庫機構已收取並已解繳國庫", "代庫機構已收取尚未解繳國庫", "機關自行收取並保管", "機關自行收取並存於機關專戶"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00557', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報之規定，政府年度會計報告之總說明（或管理者討論與分析），其內容不包含 下列何者？', '["財務報告之簡述", "財務狀況之分析", "前後年度財務資訊之比較", "財務報導之範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00558', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關投資持股10%之A公司，A公司發放年度 現金股利時，甲機關應貸記下列何者？', '["投資利益", "採權益法之投資評價調整", "其他長期投資評價調整", "投資股息紅利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00559', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '中央政府原持有S 公司25%股權，現因S 公司與B公司（政府未持股）合併，B公司為存續公 司，中央政府依換股比率換回B公司5%股權，B公司為公開上市公司。下列敘述何者正確？', '["應以B公司的公允價值認列換入的長期投資", "應以S公司的帳面金額認列換入的長期投資", "此一股權交換交易，無須將採權益法之長期投資轉列為其他長期投資", "此一股權交換交易，屬同類資產交換，不具商業實質，故不會發生投資損益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00560', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '甲機關於檔案室中發現一幅未列入財產及會計帳、署名「齊白石」的書畫捲軸，經專家鑑定為真 跡，復經甲機關所設評審委員會審議結果，以毀損無法修復為由，爰決議移交乙專業機關處理。 移交後經乙機關評估認為可加以修復並展示，修復經費100萬元。另根據蘇富比最近一次拍賣價 格，相似之書畫拍出價格為3億元。依中央政府各機關珍貴動產不動產管理要點規定，有關乙機 關的會計處理，下列何者正確？', '["認列非消耗性收藏品，並以修復經費100萬元認列為取得成本", "認列消耗性收藏品，並以3億元認列為取得成本", "認列非消耗性收藏品，並以乙機關估定之價格，作為登記價值", "應以公允價值認列消耗性收藏品，若公允價值無法可靠衡量，則僅記載數量資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00561', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，對於固定資產之會計處理，下列何者錯誤？', '["甲機關辦理建築物耐震補強工程450萬元，因增加建築物耐用年限，應借記房屋及建築科目", "乙機關中央空調系統故障，以7萬元完成修復，僅恢復正常運作，故以當期費用認列", "丙機關3年前原規劃興建7層樓行政大樓，受限於預算不足，僅興建5層樓，現因業務需要， 再增建2層樓，實際支付工程款1,000萬元，應借記房屋及建築科目", "丁機關原管有某一建物未達耐用年限，因已無須公用，故以現狀移交國有財產管理機關接管， 移出時，丁機關應以帳面金額借記資產負債淨額科目"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00562', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依據政府會計公報及中央政府普通公務會計制度一致規定，中央政府甲機關於 X1 年度完成研究 計畫，並將研究成果以技術入股方式，與民營B公司共同成立K公司。甲機關取得K公司8萬 股，每股面額10元，其餘6萬股由B公司出資1,200萬元取得。K公司成立後，第1年至第3年 分別獲利 200 萬元、500 萬元及 1,000 萬元，並於隔一年度配發現金股利 100 萬元、300 萬元及 700萬元，下列敘述何者錯誤？（持股比例計算至XX%、金額計算至萬元，以下皆四捨五入）', '["K公司為國營事業，其會計為附屬單位會計", "K公司每年度的獲利，甲機關應按投資比例認列「投資利益」及「採權益法之投資評價調整」", "至取得股權的第2年底，甲機關帳列K公司的帳面金額為1,943萬元", "至取得股權的第3年底，甲機關帳列K公司的帳面金額為2,242萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00563', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-ac2adf20', 'sub-locality-d0d1b9a2-02', NULL, 'single_choice', '依內地稅徵課會計制度之規定，其應設置之會計簿籍，不包括下列何者？', '["備查簿", "序時帳簿", "總分類帳簿", "明細分類帳簿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:10+00:00", "source_pdf_sha1": "2f24e4c86924", "answer_pdf_sha1": "b01c6334ecca", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
